<template><div class="page"><div class="header"><div><h1>重点人口管理</h1><p>建档、解除均走申请审批与显式执行闭环。</p></div><el-button v-if="canApply" type="primary" @click="openRegister">申请建档</el-button></div><el-alert v-if="error" title="重点人口记录加载失败" type="error" :closable="false" show-icon><el-button link type="primary" @click="load">重试</el-button></el-alert><el-card shadow="never"><el-table v-loading="loading" :data="records" empty-text="查询成功，暂无重点人口记录"><el-table-column prop="personName" label="姓名" width="110"/><el-table-column prop="idCard" label="身份证" min-width="180"/><el-table-column prop="populationType" label="类型" min-width="140"/><el-table-column prop="attentionLevel" label="关注等级" width="110"/><el-table-column prop="registerDate" label="建档日期" width="120"/><el-table-column prop="status" label="状态" width="100"/><el-table-column label="操作" width="160"><template #default="{row}"><el-button v-if="canApply&&row.status==='ACTIVE'" link type="danger" @click="openRelease(row)">申请解除</el-button><el-button link @click="showHistory(row)">历史</el-button></template></el-table-column></el-table><AppPagination v-model:current="query.current" v-model:size="query.size" :total="total" @change="load"/></el-card>
<FormDialog v-model:visible="visible" :title="mode==='REGISTER'?'重点人口建档申请':'重点人口解除申请'" :loading="submitting" @confirm="submit"><el-form ref="formRef" :model="form" :rules="rules" label-width="100px"><el-form-item v-if="mode==='REGISTER'" label="人员" prop="personId"><PersonSelect v-model="form.personId"/></el-form-item><el-form-item v-if="mode==='REGISTER'" label="重点类型" prop="populationType"><DictionarySelect v-model="form.populationType" type="KEY_POPULATION_TYPE"/></el-form-item><el-form-item v-if="mode==='REGISTER'" label="关注等级" prop="attentionLevel"><el-select v-model="form.attentionLevel"><el-option label="低" value="LOW"/><el-option label="中" value="MEDIUM"/><el-option label="高" value="HIGH"/></el-select></el-form-item><el-form-item label="业务日期" prop="eventDate"><el-date-picker v-model="form.eventDate" value-format="YYYY-MM-DD"/></el-form-item><el-form-item label="业务理由" prop="reason"><el-input v-model.trim="form.reason" type="textarea"/></el-form-item><el-form-item label="标题" prop="title"><el-input v-model.trim="form.title"/></el-form-item></el-form></FormDialog><el-drawer v-model="historyVisible" title="重点人口变更历史"><el-timeline><el-timeline-item v-for="x in history" :key="x.historyId" :timestamp="x.createdAt">{{ x.eventType }}：{{ x.previousStatus||'-' }} → {{ x.newStatus||'-' }}（{{ x.reason||'-' }}）</el-timeline-item></el-timeline></el-drawer></div></template>
<script setup>
import { computed,onMounted,reactive,ref } from 'vue';import { useRouter } from 'vue-router';import { ElMessage } from 'element-plus';import AppPagination from '../../components/common/AppPagination.vue';import FormDialog from '../../components/common/FormDialog.vue';import PersonSelect from '../../components/business/PersonSelect.vue';import DictionarySelect from '../../components/business/DictionarySelect.vue';import { createKeyRegisterApplication,createKeyReleaseApplication,getKeyPopulationHistory,getKeyPopulationPage } from '../../api/keyPopulations.js';import { normalizePageResult } from '../../utils/page.js';import { useUserStore } from '../../stores/user.js';import { PERMISSIONS } from '../../constants/permissions.js'
const router=useRouter(),user=useUserStore(),canApply=computed(()=>user.hasPermission(PERMISSIONS.KEY_POPULATION_APPLY));const query=reactive({current:1,size:10});const records=ref([]),total=ref(0),loading=ref(false),error=ref(false),visible=ref(false),submitting=ref(false),mode=ref('REGISTER'),selected=ref(null),formRef=ref(),historyVisible=ref(false),history=ref([]);const form=reactive({personId:null,populationType:'',attentionLevel:'MEDIUM',eventDate:'',reason:'',title:''});const rules={personId:[{required:true,message:'请选择人员'}],populationType:[{required:true,message:'请选择类型'}],attentionLevel:[{required:true,message:'请选择等级'}],eventDate:[{required:true,message:'请选择日期'}],reason:[{required:true,message:'请输入理由'}],title:[{required:true,message:'请输入标题'}]}
async function load(){loading.value=true;try{const p=normalizePageResult(await getKeyPopulationPage(query));records.value=p.records;total.value=p.total;error.value=false}catch{error.value=true}finally{loading.value=false}}function openRegister(){mode.value='REGISTER';selected.value=null;Object.assign(form,{personId:null,populationType:'',attentionLevel:'MEDIUM',eventDate:'',reason:'',title:'重点人口建档'});visible.value=true}function openRelease(row){mode.value='RELEASE';selected.value=row;Object.assign(form,{eventDate:'',reason:'',title:'重点人口解除'});visible.value=true}async function submit(){if(!await formRef.value?.validate())return;submitting.value=true;try{const result=mode.value==='REGISTER'?await createKeyRegisterApplication({personId:form.personId,populationType:form.populationType,attentionLevel:form.attentionLevel,registerReason:form.reason,registerDate:form.eventDate,title:form.title}):await createKeyReleaseApplication(selected.value.recordId,{releaseReason:form.reason,releaseDate:form.eventDate,title:form.title});ElMessage.success('专业申请已创建，请上传并核验材料后提交');visible.value=false;router.push(`/applications/${result.application.applicationId}`)}finally{submitting.value=false}}async function showHistory(row){history.value=await getKeyPopulationHistory(row.recordId);historyVisible.value=true}onMounted(load)
</script><style scoped>.page{display:flex;flex-direction:column;gap:16px}.header{display:flex;justify-content:space-between;align-items:flex-end}.header h1{margin:0 0 6px}.header p{color:var(--el-text-color-secondary)}</style>
